def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE

    try:
        modified_prs = Presentation(modified_ppt_path)
        if len(modified_prs.slides) < 14:
            return "Slide 14 not available", 0.0

        modified_slide = modified_prs.slides[13]  # 0-indexed

        # Find all text boxes and check their content
        text_boxes = [shape for shape in modified_slide.shapes 
                     if hasattr(shape, 'text_frame') and shape.shape_type == MSO_SHAPE_TYPE.TEXT_BOX]

        target_caption = "Intel Skylake Die Layout"

        for text_box in text_boxes:
            text_content = text_box.text_frame.text.strip()
            if text_content == target_caption:
                return f"Found text box with correct caption: '{target_caption}'", 1.0

        # Check if any text box contains similar content (case insensitive)
        for text_box in text_boxes:
            text_content = text_box.text_frame.text.strip()
            if target_caption.lower() in text_content.lower():
                return f"Found text box with similar caption: '{text_content}' (expected: '{target_caption}')", 0.7

        return f"No text box found with caption '{target_caption}'", 0.0

    except Exception as e:
        return f"Error checking text box content: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    try:
        # Find slide 14 screenshots
        original_screenshot = None
        modified_screenshot = None

        for screenshot in original_ppt_screenshots:
            if screenshot.slide_number == 14:
                original_screenshot = screenshot
                break

        for screenshot in modified_ppt_screenshots:
            if screenshot.slide_number == 14:
                modified_screenshot = screenshot
                break

        if not original_screenshot or not modified_screenshot:
            return "Could not find screenshots for slide 14", 0.0

        prompt = '''Compare these two PowerPoint slide images (before and after). 

The task was to add a text box with the caption "Intel Skylake Die Layout" below a processor image on slide 14.

Please analyze:
        1. Is there a processor/chip image visible in the slide?
        2. Is there a text box with "Intel Skylake Die Layout" caption?
        3. Is the text box positioned below the processor image?

Respond with:
        - "SUCCESS" if the text box is correctly positioned below the processor image
        - "PARTIAL" if the text box exists but positioning is not ideal
        - "FAILURE" if the text box is not below the processor image or doesn't exist

Then provide a brief explanation.'''

        response = vlm_call(prompt, [original_screenshot.image_path, modified_screenshot.image_path])

        if "SUCCESS" in response.upper():
            return f"Text box correctly positioned below processor image: {response}", 1.0
        elif "PARTIAL" in response.upper():
            return f"Text box positioning needs improvement: {response}", 0.6
        else:
            return f"Text box not properly positioned below processor image: {response}", 0.0

    except Exception as e:
        return f"Error checking text box positioning: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
