    removed_slides = ppt_diff.removed_slides

    # Check for added/removed slides
    if added_slides or removed_slides:
        return f"Slides were added ({len(added_slides)}) or removed ({len(removed_slides)})", 0.0

    # Check for modifications to slides other than slide 14
    other_slide_modifications = []
    for old_slide, new_slide in modified_slides:
        if new_slide.slide_number != 14:
            other_slide_modifications.append(new_slide.slide_number)

    if other_slide_modifications:
        return f"Unintended modifications detected on slides: {other_slide_modifications}", 0.0
    else:
        return "No unintended changes to other slides", 1.0
